query:
SELECT ha.*, h.name, h.scope FROM habit_assignments ha JOIN habits h ON ha.habit_id = h.id WHERE ha.user_id = 1 LIMIT 20;
SELECT COUNT(*) as total_habits FROM habits;
SELECT COUNT(*) as total_assignments FROM habit_assignments;

